import React, { useEffect, useState } from "react";
import ReactMarkDown from "react-markdown";
import md from "./mdfiles/test.md";

export const importAll = (r: __WebpackModuleApi.RequireContext) =>
  r.keys().map((fileName: string) => ({
    slug: fileName.substr(2).replace(/\/index\.mdx$/, ""),
    slug2: fileName,
    module: r(fileName),
    tt: r,
  }));

const useMarkHook = (markFilePath: string) => {
  const [source, setSource] = useState("");

  const mdList = importAll(require.context("./mdfiles/", true, /\.md$/));

  useEffect(() => {
    fetch(markFilePath)
      .then((resp) => resp.text())
      .then((text) => setSource(text));
  }, [markFilePath]);

  return [source];
};

function App() {
  const [source] = useMarkHook(md);
  return (
    <div>
      <header>Gensing github blog</header>
      <ReactMarkDown>{source}</ReactMarkDown>
    </div>
  );
}

export default App;
